const CATEGORIES=["TV e Vídeo", "Celulares", "Notebooks", "Eletrodomésticos", "Casa e Cozinha", "Climatização", "Móveis", "Colchões", "Ferramentas", "Automotivo", "Beleza", "Bebês", "Esportes", "Games", "Informática", "Áudio", "Outros"];
const $=id=>document.getElementById(id);
const normalize=s=>String(s||"").normalize("NFD").replace(/[\u0300-\u036f]/g,"").toLowerCase();
const money=v=>Number(v||0).toLocaleString("pt-BR",{style:"currency",currency:"BRL"});
const cfg=window.CUSTO_CERTO_CONFIG||{};
const db=(window.supabase&&cfg.supabaseUrl&&cfg.supabasePublishableKey)?window.supabase.createClient(cfg.supabaseUrl,cfg.supabasePublishableKey):null;
const state={products:[],query:"",category:""};

async function load(){
  let fromDb=[];
  try{
    if(!db)throw new Error("sem banco");
    const {data,error}=await db.from("offers_public").select("*").eq("active",true);
    if(error)throw error;
    fromDb=(data||[]).map(x=>({...x,is_demo:false}));
  }catch(e){console.warn(e.message)}
  state.products=fromDb.length?fromDb:DEMO_PRODUCTS;
  renderCategories();populateFilters();render();
  $("warning").classList.toggle("hidden",fromDb.length>0);
  if(!fromDb.length)$("warning").textContent="Você está vendo produtos demonstrativos. Eles usam buscas específicas nas lojas. Para abrir uma página exata de produto, cadastre ofertas reais em Cadastrar oferta ou conecte um datafeed/API.";
}

function renderCategories(){
  $("categoryBar").innerHTML='<button class="active" data-cat="">Todos</button>'+CATEGORIES.map(c=>`<button data-cat="${c}">${c}</button>`).join("");
  document.querySelectorAll("[data-cat]").forEach(b=>b.onclick=()=>{
    document.querySelectorAll("[data-cat]").forEach(x=>x.classList.remove("active"));b.classList.add("active");state.category=b.dataset.cat;render();
  });
}
function populateFilters(){
  const stores=[...new Set(state.products.map(x=>x.store))].sort(),brands=[...new Set(state.products.map(x=>x.brand).filter(Boolean))].sort();
  $("storeFilter").innerHTML='<option value="">Todas as lojas</option>'+stores.map(x=>`<option>${x}</option>`).join("");
  $("brandFilter").innerHTML='<option value="">Todas as marcas</option>'+brands.map(x=>`<option>${x}</option>`).join("");
}
function discount(x){return x.old_price&&x.old_price>x.price?Math.round((1-x.price/x.old_price)*100):0}
function filtered(){
  const q=normalize(state.query),store=$("storeFilter").value,brand=$("brandFilter").value,max=Number($("maxPrice").value||0);
  let list=state.products.filter(x=>{
    const text=normalize([x.name,x.brand,x.category,x.store].join(" "));
    return(!q||text.includes(q))&&(!state.category||x.category===state.category)&&(!store||x.store===store)&&(!brand||x.brand===brand)&&(!max||x.price<=max);
  });
  const sort=$("sortFilter").value;
  if(sort==="priceAsc")list.sort((a,b)=>a.price-b.price);
  if(sort==="discount")list.sort((a,b)=>discount(b)-discount(a));
  return list;
}
function render(){
  const list=filtered();$("grid").innerHTML="";$("count").textContent=`${list.length} produto${list.length===1?"":"s"}`; $("title").textContent=state.query?`Resultados para “${state.query}”`:state.category||"Produtos em destaque";$("empty").classList.toggle("hidden",!!list.length);
  const tpl=$("cardTpl");
  list.forEach(x=>{
    const n=tpl.content.cloneNode(true),img=n.querySelector(".img");
    img.src=x.image_url||FALLBACKS[x.category]||FALLBACKS["Outros"];img.alt=x.name;img.onerror=()=>img.src=FALLBACKS[x.category]||FALLBACKS["Outros"];
    n.querySelector(".store").textContent=x.store;n.querySelector(".name").textContent=x.name;n.querySelector(".brand").textContent=[x.brand,x.category].filter(Boolean).join(" • ");
    n.querySelector(".old").textContent=x.old_price?money(x.old_price):"";n.querySelector(".price").textContent=money(x.price);n.querySelector(".installments").textContent=x.installments||"";n.querySelector(".shipping").textContent=x.shipping_text||"Consulte o frete";
    const d=discount(x),badge=n.querySelector(".badge");if(d){badge.textContent=`${d}% OFF`;badge.classList.remove("hidden")}
    n.querySelector(".demo-label").classList.toggle("hidden",!x.is_demo);
    const buy=n.querySelector(".buy");buy.href=x.affiliate_url||x.product_url;buy.textContent=x.is_demo?"Pesquisar na loja":"Ver produto";
    $("grid").appendChild(n);
  });
}
$("searchForm").onsubmit=e=>{e.preventDefault();state.query=$("searchInput").value.trim();render();document.querySelector(".section").scrollIntoView({behavior:"smooth"})};
["storeFilter","brandFilter","maxPrice","sortFilter"].forEach(id=>$(id).addEventListener("input",render));
$("refreshBtn").onclick=load;load();